<template>
	<view class="">
		<u-navbar ref="navbar" title="生成卡密" :z-index="980" :custom-back="$util.back">
			<template #right>
				<view class="navbar-right">
					<view class="btn-item check-btn" @click="handelSaveClick">
						<u-icon name="edit-pen"></u-icon>
						<text>保存</text>
					</view>
				</view>
			</template>
		</u-navbar>
		<scroll-view @touchmove.stop :scroll-y="true" class="scroll_content" :rebound="false"
			:style="{height:scrollHeight+'px'}">
			<view class="form-box">
				<u-form :model="form" ref="uForm" :label-width="140">
					<u-form-item label="生成数量" prop="num">
						<u-number-box v-model="form.num"></u-number-box>
					</u-form-item>
					<u-form-item label="商品限价" prop="limit_price">
						<u-input v-model="form.limit_price" placeholder="商品限价默认0不限制，成本低于限价禁止兑换" />
					</u-form-item>
					<u-form-item label="过期时间" prop="expire_time">
						<uni-datetime-picker v-model="form.expire_time" type="datetime" />
					</u-form-item>
					<u-form-item label="生成备注" prop="mark">
						<u-input type="textarea" v-model="form.mark" />
					</u-form-item>
				</u-form>
			</view>
		</scroll-view>
	</view>
</template>

<script>
	export default {
		data() {
			return {
				scrollHeight: 0,

				form: {
					num: 1, //生成数量
					limit_price: '', //商品限价
					expire_time: '', //过期时间
					mark: '',
					batch_id: '', //卡组ID
				},
				rules: {
					// name: [{
					// 	required: true,
					// 	message: '请输入名称',
					// 	trigger: ['change', 'blur']
					// }],
					// goods_id: [{
					// 	type: 'array',
					// 	required: true,
					// 	message: '请选择商品',
					// 	trigger: ['change', 'blur']
					// }]
				},
			};
		},
		onReady() {
			this.$refs.uForm.setRules(this.rules)
			this.$nextTick(() => {
				uni.createSelectorQuery().select(".scroll_content").boundingClientRect(res => {
					this.scrollHeight = this.deviceInfo.screenHeight - res.top
				}).exec()
			})
		},
		onLoad(e) {
			const {
				id
			} = e
			if (!id) {
				this.$util.msg('卡组id不能为空')
				setTimeout(() => {
					this.$util.back()
				}, 500)
				return
			}
			this.form.batch_id = id
		},
		methods: {
			// 保存点击
			handelSaveClick() {
				this.$u.throttle(async () => {
					await this.$u.api.createCard(this.form)
					this.$util.back()
				}, 1000)
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.navbar-right {
		margin-right: 18rpx;
		display: flex;
		gap: 20rpx;

		.btn-item {}

		.btn-item:active {
			opacity: .6;
		}
	}

	.form-box {
		background-color: #fff;
		padding: 0 20rpx;
	}

	.check-btn {
		padding: 4rpx 20rpx;
		background: linear-gradient(-90deg, #19be6b, #19be6b);
		border-radius: 44rpx;
		color: #fff;
	}

	::v-deep {
		.u-sticky-wrap {
			height: auto !important;
		}

		.uni-input-wrapper {
			font-size: 26rpx;
		}

		.uni-textarea-compute {
			font-size: 26rpx;
		}

		.u-form-item {
			font-size: 26rpx;
		}

		.uni-date-x {
			border-radius: 56rpx;

			.icon-calendar {
				padding-left: 24rpx;
			}
		}

		.uni-date-x--border {
			border-radius: 56rpx;
		}

		.uni-date__x-input {
			line-height: 60rpx;
			height: 60rpx;
		}

		.uni-input-input {
			font-size: 26rpx;
		}

		.u-size-default {
			font-size: 26rpx;
			height: 60rpx;
			line-height: 58rpx;
			padding: 0 80rpx;
			margin-top: 26rpx;
			background: linear-gradient(90deg, #FE8A56 0%, #FF504B 100%);
			border-radius: 60rpx;
			color: #fff;
		}

		.fail {
			background: linear-gradient(90deg, #353535 0%, #909399 100%);
		}

		.u-hairline-border::after {
			border-radius: 60rpx;
		}
	}
</style>